const result = $input.first().json;

if (!result.success || !result.reports) {
  return [{ json: { skip: true, reason: 'No data' } }];
}

const reports = result.reports;
const criticalAgents = reports.filter(r => r.performance.successRate < 80);
const recommendations = reports.flatMap(r => r.recommendations.map(rec => `${r.agentName}: ${rec}`));

const blocks = [
  `*Weekly Agent Optimization Report — ${new Date().toISOString().split('T')[0]}*`,
  '',
  `Agents Analyzed: ${reports.length}`,
  `Avg Success Rate: ${result.summary.avgSuccessRate}%`,
  `Total Recommendations: ${result.summary.totalRecommendations}`,
  `Error Patterns Found: ${result.summary.totalErrorPatterns}`,
];

if (criticalAgents.length > 0) {
  blocks.push('', '*Agents Needing Attention:*');
  criticalAgents.forEach(a => {
    blocks.push(`  :warning: ${a.agentName}: ${a.performance.successRate}% success (${a.performance.totalTasks} tasks)`);
  });
}

if (recommendations.length > 0) {
  blocks.push('', '*Top Recommendations:*');
  recommendations.slice(0, 10).forEach(r => blocks.push(`  • ${r}`));
}

return [{ json: { formattedMessage: blocks.join('\n'), skip: false, reportCount: reports.length } }];

const data = $input.first().json;
if (data.skip) {
  console.log('Skipping notification — no data');
  return [{ json: { delivered: false } }];
}

// In production: send via Slack webhook
console.log('Weekly Optimization Report:', data.formattedMessage);

return [{ json: { delivered: true, sentAt: new Date().toISOString() } }];
